#include <bits/stdc++.h>
using namespace std;
long long n,m,a[1003][1003],b[1003][1003];
double sa[1003],sb[1003],c[1003];
int k=0,ans1[1000006],ans2[1000006];
int main(){
    cin>>m>>n;
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++){
			cin>>a[i][j];
			sa[i]+=a[i][j];
		}
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++){
    		cin>>b[i][j];
    		sb[i]+=b[i][j];
    	}
    for(int i=1;i<=n;i++){
    	for(int j=1;j<=m;j++)
    		c[i]+=((double)a[i][j]-sa[i]/m)*((double)a[i][j]-sa[i]/m)+((double)b[i][j]-sb[i]/m)*((double)b[i][j]-sb[i]/m);
		c[i]/=m;
	}
	for(int i=1;i<=n;i++)
		for(int j=i+1;j<=n;j++)
			if(c[i]>c[j])
				swap(c[i],c[j]),ans1[++k]=i,ans2[k]=j;
	cout<<k<<endl;
	for(int i=1;i<=k;i++)
		cout<<ans1[i]<<' '<<ans2[i]<<endl;
    return 0;
}
